     2→ * Content Infrastructure — Session-Scoped Entitlement Cache
     3→ *
     4→ * In-memory TTL cache for resolved entitlements. Avoids repeated external
     5→ * calls within a session. No external cache dependency for MVP.
     6→ */
     7→
     8→import type { ResolvedEntitlements } from '../types.js';
     9→
    10→// ============================================================
    11→// INTERNAL TYPES
    12→// ============================================================
    13→
    14→interface CachedEntitlements {
    15→  entitlements: ResolvedEntitlements;
    16→  /** Unix timestamp (ms) at which this entry expires */
    17→  expiresAt: number;
    18→}
    19→
    20→// ============================================================
    21→// CACHE
    22→// ============================================================
    23→
    24→export class EntitlementCache {
    25→  private readonly cache = new Map<string, CachedEntitlements>();
    26→
    27→  /**
    28→   * Return cached entitlements for sessionId, or null if absent / expired.
    29→   */
    30→  get(sessionId: string): ResolvedEntitlements | null {
    31→    const entry = this.cache.get(sessionId);
    32→    if (!entry) return null;
    33→    if (Date.now() > entry.expiresAt) {
    34→      this.cache.delete(sessionId);
    35→      return null;
    36→    }
    37→    return entry.entitlements;
    38→  }
    39→
    40→  /**
    41→   * Store entitlements for sessionId. TTL is taken from entitlements.ttlSeconds
    42→   * when present, otherwise defaults to 3600s.
    43→   */
    44→  set(sessionId: string, entitlements: ResolvedEntitlements): void {
    45→    const ttlSeconds = entitlements.ttlSeconds ?? 3600;
    46→    const expiresAt = Date.now() + ttlSeconds * 1000;
    47→    this.cache.set(sessionId, { entitlements, expiresAt });
    48→  }
    49→
    50→  /**
    51→   * Remove entitlements for a specific session (e.g., on session end or
    52→   * forced re-resolution).
    53→   */
    54→  invalidate(sessionId: string): void {
    55→    this.cache.delete(sessionId);
    56→  }
    57→
    58→  /**
    59→   * Remove all expired entries. Should be called periodically by a scheduler
    60→   * or cleanup interval to prevent unbounded memory growth.
    61→   */
    62→  cleanup(): void {
    63→    const now = Date.now();
    64→    for (const [key, entry] of this.cache.entries()) {
    65→      if (now > entry.expiresAt) {
    66→        this.cache.delete(key);
    67→      }
    68→    }
    69→  }
    70→
    71→  /** Current number of cached sessions (including potentially expired ones). */
    72→  get size(): number {
    73→    return this.cache.size;
    74→  }
    75→}
    76→"}]},"uuid":"2b1ab0dd-094b-4644-a5d5-3f366c0718f4","timestamp":"2026-03-20T12:44:03.715Z","sourceToolAssistantUUID":"fd8b081f-391e-4a31-9f78-f29fd7aadddb","userType":"external","entrypoint":"cli","cwd":"/Users/AlexUA/claude/joyus-ai","sessionId":"e2ac6498-e3c5-4d3b-b9db-1cd6b8682933","version":"2.1.80","gitBranch":"main","slug":"sparkling-cooking-muffin"}
