{"parentUuid":"baaad936-b70a-4ffb-acf1-7f101c977fad","isSidechain":true,"promptId":"241f3f1c-99f9-4efd-b0db-e4563eeda935","agentId":"ad861be1494a9ff53","type":"user","message":{"role":"user","content":[{"tool_use_id":"toolu_01BgHPM1nurUwSd6gBrTHuX6","type":"tool_result","content":"     1→/**
     2→ * Content Infrastructure — HTTP Entitlement Resolver
     3→ *
     4→ * Generic HTTP-based resolver that queries any REST endpoint for
     5→ * user entitlements. Supports GET and POST, three auth types, and
     6→ * configurable response field mapping.
     7→ *
     8→ * SC-004: Resolution must complete <500ms. Default timeout: 2000ms (conservative).
     9→ */
    10→
    11→import axios, { type AxiosRequestConfig } from 'axios';
    12→
    13→import type { ResolvedEntitlements } from '../types.js';
    14→import type {
    15→  EntitlementResolver,
    16→  EntitlementResolverConfig,
    17→  ResolverContext,
    18→} from './interface.js';
    19→
    20→// ============================================================
    21→// CONFIG
    22→// ============================================================
    23→
    24→export interface HttpResolverConfig extends EntitlementResolverConfig {
    25→  baseUrl: string;
    26→  endpoint: string;
    27→  method: 'GET' | 'POST';
    28→  authType: 'none' | 'bearer' | 'api-key';
    29→  /** Encrypted auth credential (bearer token or API key value) */
    30→  authValue?: string;
    31→  /** Header name for api-key auth type. Defaults to 'X-Api-Key'. */
    32→  apiKeyHeader?: string;
    33→  timeoutMs: number;
    34→  responseMapping: {
    35→    /** Top-level field name in the JSON response that contains the products array */
    36→    productsField: string;
    37→    /** Optional top-level field name for TTL value (seconds) */
    38→    ttlField?: string;
    39→  };
    40→}
    41→
    42→// ============================================================
    43→// IMPLEMENTATION
    44→// ============================================================
    45→
    46→export class HttpEntitlementResolver implements EntitlementResolver {
    47→  constructor(private readonly config: HttpResolverConfig) {}
    48→
    49→  async resolve(
    50→    userId: string,
    51→    tenantId: string,
    52→    context: ResolverContext,
    53→  ): Promise<ResolvedEntitlements> {
    54→    const url = `${this.config.baseUrl.replace(/\/$/, '')}/${this.config.endpoint.replace(/^\//, '')}`;
    55→
    56→    const requestConfig: AxiosRequestConfig = {
    57→      method: this.config.method,
    58→      url,
    59→      timeout: this.config.timeoutMs ?? 2000,
    60→      headers: this.buildHeaders(),
    61→    };
    62→
    63→    if (this.config.method === 'GET') {
    64→      requestConfig.params = { userId, tenantId, sessionId: context.sessionId };
    65→    } else {
    66→      requestConfig.data = { userId, tenantId, sessionId: context.sessionId };
    67→    }
    68→
    69→    let response: Record<string, unknown>;
    70→    try {
    71→      const res = await axios(requestConfig);
    72→      response = res.data as Record<string, unknown>;
    73→    } catch (err) {
    74→      if (axios.isAxiosError(err)) {
    75→        if (err.code === 'ECONNABORTED') {
    76→          throw new Error(`Entitlement resolver timed out after ${this.config.timeoutMs}ms`);
    77→        }
    78→        const status = err.response?.status ?? 0;
    79→        if (status >= 400 && status < 500) {
    80→          throw new Error(`Entitlement resolver returned client error: ${status}`);
    81→        }
    82→        if (status >= 500) {
    83→          throw new Error(`Entitlement resolver returned server error: ${status}`);
    84→        }
    85→      }
    86→      throw new Error('Entitlement resolver request failed');
    87→    }
    88→
    89→    const rawProducts = response[this.config.responseMapping.productsField];
    90→    if (!Array.isArray(rawProducts)) {
    91→      throw new Error(
    92→        `Entitlement resolver response missing expected field: ${this.config.responseMapping.productsField}`,
    93→      );
    94→    }
    95→    const productIds = rawProducts.filter((p): p is string => typeof p === 'string');
    96→
    97→    let ttlSeconds = this.config.defaultTtlSeconds;
    98→    if (this.config.responseMapping.ttlField) {
    99→      const rawTtl = response[this.config.responseMapping.ttlField];
   100→      if (typeof rawTtl === 'number' && rawTtl > 0) {
   101→        ttlSeconds = rawTtl;
   102→      }
   103→    }
   104→
   105→    return {
   106→      productIds,
   107→      sourceIds: [],   // Populated by EntitlementService after DB join
   108→      profileIds: [],  // Populated by EntitlementService after DB join
   109→      resolvedFrom: this.config.name,
   110→      resolvedAt: new Date(),
   111→      ttlSeconds,
   112→    };
   113→  }
   114→
   115→  private buildHeaders(): Record<string, string> {
   116→    const headers: Record<string, string> = {
   117→      'Content-Type': 'application/json',
   118→    };
   119→
   120→    switch (this.config.authType) {
   121→      case 'bearer':
   122→        if (this.config.authValue) {
   123→          headers['Authorization'] = `Bearer ${this.config.authValue}`;
   124→        }
   125→        break;
   126→      case 'api-key': {
   127→        const headerName = this.config.apiKeyHeader ?? 'X-Api-Key';
   128→        if (this.config.authValue) {
   129→          headers[headerName] = this.config.authValue;
   130→        }
   131→        break;
   132→      }
   133→      case 'none':
   134→      default:
   135→        break;
   136→    }
   137→
   138→    return headers;
   139→  }
   140→}
   141→"}]},"uuid":"7453cb75-98dc-454e-ac43-ae040ff0a1a6","timestamp":"2026-03-20T12:44:04.252Z","sourceToolAssistantUUID":"baaad936-b70a-4ffb-acf1-7f101c977fad","userType":"external","entrypoint":"cli","cwd":"/Users/AlexUA/claude/joyus-ai","sessionId":"e2ac6498-e3c5-4d3b-b9db-1cd6b8682933","version":"2.1.80","gitBranch":"main","slug":"sparkling-cooking-muffin"}
