## Fix 1: Replace CryptoJS with Node native crypto + fail-closed
**File:** `src/db/encryption.ts`

Replace CryptoJS AES (passphrase mode, single-iteration MD5 KDF) with Node.js native `crypto` using AES-256-GCM with random IV and auth tag. Make the module fail-closed: if `TOKEN_ENCRYPTION_KEY` is not set, throw at module load (not at call time). Remove the `crypto-js` import.

Use this pattern:
```typescript
import crypto from 'node:crypto';

const ALGORITHM = 'aes-256-gcm';
const IV_LENGTH = 16;

const ENCRYPTION_KEY = process.env.TOKEN_ENCRYPTION_KEY;
if (!ENCRYPTION_KEY) {
  if (process.env.NODE_ENV === 'production') {
    throw new Error('FATAL: TOKEN_ENCRYPTION_KEY is required in production');
  }
  console.warn('[joyus] TOKEN_ENCRYPTION_KEY not set - using development fallback');
}

export function encryptToken(token: string): string {
  if (!ENCRYPTION_KEY) return token; // Dev-only fallback
  const key = Buffer.from(ENCRYPTION_KEY, 'hex');
  const iv = crypto.randomBytes(IV_LENGTH);
  const cipher = crypto.createCipheriv(ALGORITHM, key, iv);
  const encrypted = Buffer.concat([cipher.update(token, 'utf8'), cipher.final()]);
  const tag = cipher.getAuthTag();
  return `${iv.toString('hex')}:${tag.toString('hex')}:${encrypted.toString('hex')}`;
}

export function decryptToken(stored: string): string {
  if (!ENCRYPTION_KEY) return stored; // Dev-only fallback
  const [ivHex, tagHex, encHex] = stored.split(':');
  if (!ivHex || !tagHex || !encHex) return stored; // Legacy plaintext fallback
  const key = Buffer.from(ENCRYPTION_KEY, 'hex');
  const decipher = crypto.createDecipheriv(ALGORITHM, key, Buffer.from(ivHex, 'hex'));
  decipher.setAuthTag(Buffer.from(tagHex, 'hex'));
  return decipher.update(Buffer.from(encHex, 'hex'), undefined, 'utf8') + decipher.final('utf8');
}
```

After modifying, check if `crypto-js` is still used elsewhere. If not, note it can be removed from package.json (but do NOT run npm uninstall — just note it).

